1317     return Def->replaceAllUsesWith(Plan->getFalse());
1318 
1319   if (match(Def, m_Select(m_VPValue(), m_VPValue(X), m_Deferred(X))))
1320     return Def->replaceAllUsesWith(X);
1321 
1322   // select c, false, true -> not c
1323   VPValue *C;
1324   if (match(Def, m_Select(m_VPValue(C), m_False(), m_True())))
1325     return Def->replaceAllUsesWith(Builder.createNot(C));
1326 
1327   // select !c, x, y -> select c, y, x
1328   if (match(Def, m_Select(m_Not(m_VPValue(C)), m_VPValue(X), m_VPValue(Y)))) {
1329     Def->setOperand(0, C);
1330     Def->setOperand(1, Y);
1331     Def->setOperand(2, X);
1332     return;
1333   }
1334 
1335   // Reassociate (x && y) && z -> x && (y && z) if x has multiple users. With
