1342         Builder.createLogicalAnd(X, Builder.createLogicalAnd(Y, Z)));
1343 
1344   if (match(Def, m_c_Add(m_VPValue(A), m_ZeroInt())))
1345     return Def->replaceAllUsesWith(A);
1346 
1347   if (match(Def, m_c_Mul(m_VPValue(A), m_One())))
1348     return Def->replaceAllUsesWith(A);
1349 
1350   if (match(Def, m_c_Mul(m_VPValue(A), m_ZeroInt())))
