1354   const APInt *APC;
1355   if (match(Def, m_c_Mul(m_VPValue(A), m_APInt(APC))) && APC->isPowerOf2())
1356     return Def->replaceAllUsesWith(Builder.createNaryOp(
1357         Instruction::Shl,
1358         {A, Plan->getConstantInt(APC->getBitWidth(), APC->exactLogBase2())},
1359         *cast<VPRecipeWithIRFlags>(Def), Def->getDebugLoc()));
1360 
1361   // Don't convert udiv to lshr inside a replicate region, as VPInstructions are
1362   // not allowed in them.
1363   const VPRegionBlock *ParentRegion = Def->getParent()->getParent();
1364   bool IsInReplicateRegion = ParentRegion && ParentRegion->isReplicator();
1365   if (!IsInReplicateRegion && match(Def, m_UDiv(m_VPValue(A), m_APInt(APC))) &&
1366       APC->isPowerOf2())
1367     return Def->replaceAllUsesWith(Builder.createNaryOp(
1368         Instruction::LShr,
1369         {A, Plan->getConstantInt(APC->getBitWidth(), APC->exactLogBase2())},
1370         *cast<VPRecipeWithIRFlags>(Def), Def->getDebugLoc()));
1371 
1372   if (match(Def, m_Not(m_VPValue(A)))) {
1373     if (match(A, m_Not(m_VPValue(A))))
1374       return Def->replaceAllUsesWith(A);
1375 
1376     // Try to fold Not into compares by adjusting the predicate in-place.
1377     CmpPredicate Pred;
1378     if (match(A, m_Cmp(Pred, m_VPValue(), m_VPValue()))) {
1379       auto *Cmp = cast<VPRecipeWithIRFlags>(A);
1380       if (all_of(Cmp->users(),
1381                  match_fn(m_CombineOr(
1382                      m_Not(m_Specific(Cmp)),
1383                      m_Select(m_Specific(Cmp), m_VPValue(), m_VPValue()))))) {
1384         Cmp->setPredicate(CmpInst::getInversePredicate(Pred));
1385         for (VPUser *U : to_vector(Cmp->users())) {
1386           auto *R = cast<VPSingleDefRecipe>(U);
1387           if (match(R, m_Select(m_Specific(Cmp), m_VPValue(X), m_VPValue(Y)))) {
1388             // select (cmp pred), x, y -> select (cmp inv_pred), y, x
1389             R->setOperand(1, Y);
1390             R->setOperand(2, X);
1391           } else {
1392             // not (cmp pred) -> cmp inv_pred
1393             assert(match(R, m_Not(m_Specific(Cmp))) && "Unexpected user");
1394             R->replaceAllUsesWith(Cmp);
1395           }
1396         }
1397         // If Cmp doesn't have a debug location, use the one from the negation,
1398         // to preserve the location.
1399         if (!Cmp->getDebugLoc() && Def->getDebugLoc())
