1401       }
1402     }
1403   }
1404 
1405   // Fold any-of (fcmp uno %A, %A), (fcmp uno %B, %B), ... ->
1406   //      any-of (fcmp uno %A, %B), ...
1407   if (match(Def, m_AnyOf())) {
1408     SmallVector<VPValue *, 4> NewOps;
1409     VPRecipeBase *UnpairedCmp = nullptr;
1410     for (VPValue *Op : Def->operands()) {
1411       VPValue *X;
1412       if (Op->getNumUsers() > 1 ||
1413           !match(Op, m_SpecificCmp(CmpInst::FCMP_UNO, m_VPValue(X),
1414                                    m_Deferred(X)))) {
1415         NewOps.push_back(Op);
1416       } else if (!UnpairedCmp) {
1417         UnpairedCmp = Op->getDefiningRecipe();
1418       } else {
1419         NewOps.push_back(Builder.createFCmp(CmpInst::FCMP_UNO,
1420                                             UnpairedCmp->getOperand(0), X));
1421         UnpairedCmp = nullptr;
1422       }
1423     }
1424 
1425     if (UnpairedCmp)
1426       NewOps.push_back(UnpairedCmp->getVPSingleValue());
1427 
1428     if (NewOps.size() < Def->getNumOperands()) {
1429       VPValue *NewAnyOf = Builder.createNaryOp(VPInstruction::AnyOf, NewOps);
1430       return Def->replaceAllUsesWith(NewAnyOf);
1431     }
1432   }
1433 
1434   // Fold (fcmp uno %X, %X) or (fcmp uno %Y, %Y) -> fcmp uno %X, %Y
1435   // This is useful for fmax/fmin without fast-math flags, where we need to
1436   // check if any operand is NaN.
1437   if (match(Def, m_BinaryOr(m_SpecificCmp(CmpInst::FCMP_UNO, m_VPValue(X),
1438                                           m_Deferred(X)),
1439                             m_SpecificCmp(CmpInst::FCMP_UNO, m_VPValue(Y),
1440                                           m_Deferred(Y))))) {
1441     VPValue *NewCmp = Builder.createFCmp(CmpInst::FCMP_UNO, X, Y);
1442     return Def->replaceAllUsesWith(NewCmp);
1443   }
